import Geschichte from '../geschichte';

export default function GeschichteLavendel() {
    return (
        <Geschichte
            id="geschichten/lavendel"
            imgs={['0.jpg', '1.jpg', '2.jpg', '3.jpg', '4.jpg']}
        >
            <h3>
                Heimatliebe - <br />
                Petite Provence in Ostwestfalen
            </h3>
            <br />
            <br />
            Immer wieder gern starten wir im Juli zu einem Ausflug in die
            HEIMISCHEN Lavendelfelder - manchmal sogar mit dem Fahrrad. Der Duft
            der blauen Blumen verzaubert uns. Wir fühlen uns wie GOTT IN
            FRANKREICH. Stundenlang sitzen wir auf der angrenzenden Wiese und
            GENIESSEN den Blick in die LILA LANDSCHAFT. Ein Traum. <br />
            An einer zum{' '}
            <a href="https://taoasis.com/" target="_blank">
                Verkaufsladen
            </a>{' '}
            umgebauten Ape stöbern wir nach allerlei hübschen und nützlichen -
            aus LAVENDEL hergestellten - Kleinigkeiten: Öl, Tee, Seife,
            Mückenstift, Wäschesäckchen... Soooooo schööööön! <br />
            Was wir manchmal echt vermissen: köstliches französches Essen -
            Tarte, Cidre, Galettes, ein guter Wein.... Bis es dort etwas
            Leckeres zu schmausen gibt, packen wir unseren Rucksack oder
            Picknick-Korb. <br />
            <br />
            Welch GLÜCK, den Urlaub direkt vor der Haustür zu haben...
            <br />
            <br />
            <a href="/rezepte/?search=%2523lavendelfeld" target="_blank">
                Zu den Rezepten
            </a>
        </Geschichte>
    );
}
