import Geschichte from '../geschichte';

export default function GeschichteGruenkohl() {
    return (
        <Geschichte id="geschichten/gruenkohl" imgs={['gruenkohl.jpg']}>
            Auch der Weg ist das Ziel...
            <br />
            <br />
            <h3>KOHL-UND-PINKEL-TOUR</h3>
            <br />
            Wenn du uns im Januar oder Februar gut gelaunt mit BOLLERWAGEN und
            vielen lieben Freunden, Kind und Kegel, auf Feldwegen triffst,
            eingemummelt in dicke Winterjacken, mit langem Schal und
            BOMMELMÜTZE, einem Punsch oder heißen Kakao in der Hand, kleinen
            Köstlichkeiten im Rucksack - schließe dich uns an! Bestimmt sind wir
            auf dem Weg zum Grünkohlessen... Denn Grünkohl liebt die Kälte und
            schmeckt nach dem ERSTEN FROST am besten. <br />
            <br />
            Ostwestfälisch kühl, Nieselregen, Schnee. Nichts hält uns ab, zu
            diesem fast 150 JAHRE ALTEN BRAUCH - neben uns in Ostwestfalen lebt
            man ihn auch in Norddeutschland, in Teilen Skandinaviens und in den
            Niederlanden - zu starten! Es geht nicht darum, zackig zur
            Gaststätte im Nachbarort zu gelangen, wo der Grünkohl serviert wird.
            Nein, es geht um eine schöne Zeit an der frischen Winterluft mit
            unseren LIEBLINGSMENSCHEN an der Seite. Deshalb halten wir immer
            'mal wieder an, um gemeinsam zu trinken, zu naschen, zu lachen. Der
            Bollerwagen transportiert nicht nur kleine Kinder... Ältere werden
            mit kleinen Spielen zu großen Märschen animiert und wachsen. "Ein
            Hut, ein Stock, ein Re-gen-schirm! Und: Vorwärts, rückwärts,
            seitwärts, 'ran, hoch, 'runter, zick-zack!". Quer durch den Wald. Am
            FORSTHAUS vorbei. Enlang an Bächen. Über die Brücke. Hat man den
            steilen Berg erklommen, ist das Ziel im Visier. Für Frostbeulen
            wärmstens zu empfehlen - der Klassiker geht immer, den mag jeder,
            der verbindet. Kein Wunder also, dass sich alle Wanderer ZUFRIEDEN
            in den Armen liegen, wenn der Grünkohl, die gerösteten kleinen
            Kartöffelchen, Kasseler, Kohlwurst und viele, viele LÖFFEL SENF
            verspeist sind! Wir lieben unsere Tradition und pflegen sie seit
            Jahrzehnten; immer wieder kleines GLÜCK...
            <br />
            <br />
            <a href="/rezepte/?search=%2523kohltour" target="_blank">
                Zu den Rezepten
            </a>
        </Geschichte>
    );
}
