import Geschichte from '../geschichte';

export default function GeschichteOuttakes() {
    return (
        <Geschichte
            id="geschichten/outtakes"
            imgs={['0.jpg', '1.jpg', '2.jpg']}
        >
            <h3>
                KITCHEN-STORIES
                <br />
                oder
                <br />
                "Das letzte Wort hat der Hunger"!
            </h3>
            <br />
            Vermessen, verschätzt, vergessen, verwechselt, verrührt, verquirlt,
            verschmolzen, verkocht, verbrannt, versiebt, verliebt, versalzen,
            ... <br />
            <br />
            Nicht alles, was wir gern zubereiten möchten, gelingt uns am Ende!
            Und eigentlich ist das auch ganz schön so. Denn so haben wir
            tatsächlich immer wieder einen Grund zum LACHEN oder stoßen völlig
            unerwartet auf neue Rezeptideen. <br />
            <br />
            "Serendipität" nennt man es, wenn eine NEUENTDECKUNG DURCH ZUFALL
            oder auf der Suche nach etwas völlig anderem gelingt. KULINARISCHE
            UNFÄLLE, wie etwa ein missglückter Pfannkuchen oder ein schimmeliger
            Käse, sind schließlich auch die Basis für köstliche Spezialitäten
            wie den Kaiserschmarrn oder Roquefort-Käse gewesen. <br />
            <br />
            Deshalb: Sei mutig und wage dich an alles, worauf du Lust hast! Nimm
            nichts zu schwer und sei nicht perfekt! So macht das Werkeln in der
            Küche - vielleicht sogar mit Freunden - noch viel, viel mehr Spaß!
            Und denke daran: Die besten Parties finden immer in der Küche
            statt... <br />
            <br />
            Spaß wünschen wir dir an dieser Stelle ganz besonders mit unseren
            OUTTAKES. Gern notieren wir das Rezept dazu, schreiben auf, welches
            löffelweise Glück es eigentlich werden sollte und dann sind wir
            gespannt, was du daraus machst! Wir freuen uns auf deine Fotos an
            "lecker(at)loeffelweise-glueck.de". <br />
            <br />
            <br />
            <a href="/rezepte/?search=%2523outtakes" target="_blank">
                Zu den Rezepten
            </a>
        </Geschichte>
    );
}
